var tipuesearch = {"pages":[{"title":"このブログについて","text":"","tags":"pages","url":"https://mizunashi-mana.github.io/blog/pages/about.html","loc":"https://mizunashi-mana.github.io/blog/pages/about.html"},{"title":"Privacy Policy","text":"","tags":"pages","url":"https://mizunashi-mana.github.io/blog/pages/privacy-policy.html","loc":"https://mizunashi-mana.github.io/blog/pages/privacy-policy.html"},{"title":"著者について","text":"雑にプログラム書いたりしてる．お金が欲しい．","tags":"pages","url":"https://mizunashi-mana.github.io/blog/pages/profile.html","loc":"https://mizunashi-mana.github.io/blog/pages/profile.html"},{"title":"ブログ始めました","text":"色々あって，技術的なことを書くブログを始めようと思いました(まる)． 今までは， Advent Calendar の時期だけ Qiita に記事を書いてたりしたんですが， ちゃんとしてないやつも書いていこうかなってことで． ちゃんとした系の記事は，出来るだけ外部に出していこうと思いますが， 調査不足だったり，よく分からない系とか徒然なるままな感じのことだったりとか，あと主に自分のためにしたこととかを書いていこうと思います． で，早速ですが一応ブログ立てたんで，立てる際した事とかを書いていきます． サイトジェネレータの選定基準 他にやりたいこと 現状幾つか解決したい問題と追加したい機能もあって， VSCode の reStructuredText プラグインのアンダーライン補完が日本語だとうまく動かないので，これを修正したい． 全文検索に対応したい． 各メニューを日本語対応させたい． シェアボタンを追加したい． Google Analytics 追加 ぐらいはやりたい． VSCode の件は，プラグインは日本語文字の width を 1 とカウントしているのに対し， docutils の方は East-Asian Width を考慮して換算してるっぽくて [1] ， 結果補完されるアンダーラインが短い判定を受けてしまうという感じです． これぐらいならすぐ直せそうなので，近いうちに PR を送ると思います． 全文検索は， Tipue Search 用の JSON を吐き出してくれるプラグインが既にあるっぽくて [2] ， 後はテーマが対応していれば問題ないみたい． しかも，使ってるテーマのイシューに検索対応したいみたいなことが 書いてある ． なのでこちらも近いうちに， PR 送ってみようかなと． 後メニュー日本語対応は， https://github.com/alexandrevicenzi/Flex/blob/v2.2.0/translations/en/LC_MESSAGES/messages.po の翻訳版を投げれば良さそうなので，これも近いうちにやる． シェアボタンを表示する仕組みはテーマにはなさそう． Disqus を追加するとついでに付いてくるやつで凌ごうか悩み中． Google Analytics はアカウント設定がちょっと億劫でやってないけど，そのうちやる． (やるとは言っていない) あまり乗り気じゃないもの 以下は一応考えてはいるけど，現状あんまり乗り気じゃないもの． 広告表示 コメント機能 全部テーマで対応してるので，それほど追加は手間ではないんだけど，とりあえず様子見． 広告表示は，収益出るようだったら Google Adsense とか設置したいけど，今はいいかな． コメント機能も Disqus を登録すればいいんだけど， Disqus 利用者そんなにいなさそうだしはてなブックマークとかで良さそう． まとめ とりあえず，雑に続けていければなと思うので，よろしくお願いします． Footnotes [1] https://github.com/docutils-mirror/docutils/blob/e88c5fb08d5cdfa8b4ac1020dd6f7177778d5990/docutils/utils/__init__.py#L628to [2] https://github.com/getpelican/pelican-plugins/tree/master/tipue_search","tags":"運用","url":"https://mizunashi-mana.github.io/blog/posts/2019/03/start-blog/","loc":"https://mizunashi-mana.github.io/blog/posts/2019/03/start-blog/"}]};